sql:
SELECT AVG(origin_count) AS avg_origin_count
FROM (
  SELECT signal_id, COUNT(origin_id) AS origin_count
  FROM signal_origin_relationships
  GROUP BY signal_id
);

SELECT signal_id, name
FROM chemical_signals
ORDER BY molecular_weight DESC;

SELECT origin_name, description
FROM origins
ORDER BY origin_name DESC;

external_knowledge:
- 'Most highly rated' refers to the chemical signals with the highest average ratings;
- The average rating is calculated based on ratings from studies that include the chemical signals;
- 'Origin' refers to the source of the chemical signal, such as female urine or male bladder urine.

- High-molecular-weight chemical signals are those with a molecular weight greater than 100;
- University-affiliated researchers are those whose institutions contain the word "University" in their names;
- The diversity of origins refers to the number of different sources (e.g., types of urine) from which the chemical signals are derived;
- The average rating is a measure of the study's overall quality and impact, typically on a scale from 1 to 5.
